import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
import requests
import os

# Initialize the BlobServiceClient and CosmosClient
blob_service_client = BlobServiceClient.from_connection_string(os.getenv("AZURE_STORAGE_CONNECTION_STRING"))
cosmos_client = CosmosClient(os.getenv("COSMOS_DB_ENDPOINT"), credential=os.getenv("COSMOS_DB_KEY"))
database_name = os.getenv("COSMOS_DB_DATABASE_NAME")
container_name = os.getenv("COSMOS_DB_CONTAINER_NAME")
event_grid_endpoint = os.getenv("EVENT_GRID_ENDPOINT")
event_grid_key = os.getenv("EVENT_GRID_KEY")

def main(event: func.EventGridEvent):
    logging.info('Processing blob event: %s', event.get_json())
    
    # Get Blob details
    blob_url = event.get_json().get('data').get('url')
    blob_name = blob_url.split('/')[-1]
    
    # Read Blob content
    blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
    blob_data = blob_client.download_blob().readall()
    
    # Process Blob data (this is just a placeholder for actual processing logic)
    processed_data = process_blob_data(blob_data)
    
    # Write results to Cosmos DB
    write_to_cosmos_db(blob_name, processed_data)
    
    # Send notification to Event Grid
    send_event_grid_notification(blob_name, processed_data)

def process_blob_data(data):
    # Placeholder for processing logic
    return data.decode('utf-8').upper()  # Example transformation

def write_to_cosmos_db(blob_name, processed_data):
    database = cosmos_client.get_database_client(database_name)
    container = database.get_container_client(container_name)
    
    item = {
        'id': blob_name,
        'processed_data': processed_data
    }
    container.upsert_item(item)

def send_event_grid_notification(blob_name, processed_data):
    headers = {
        'aeg-sas-key': event_grid_key,
        'Content-Type': 'application/json'
    }
    event_data = {
        'id': blob_name,
        'eventType': 'BlobProcessed',
        'subject': 'Blob Storage',
        'eventTime': func.datetime.utcnow().isoformat(),
        'data': {
            'blobName': blob_name,
            'processedData': processed_data
        },
        'dataVersion': '1.0'
    }
    response = requests.post(event_grid_endpoint, json=[event_data], headers=headers)
    response.raise_for_status()